import { FunctionComponent, VNode } from 'preact';
import {
  HTMLAttributes,
  useState,
  useMemo,
  useCallback,
  useEffect,
  JSX,
  ChangeEvent,
} from 'preact/compat';
import { classes } from '@adobe-commerce/elsie/lib';
import { useText } from '@adobe-commerce/elsie/i18n';
import {
  ColorSwatch,
  ImageSwatch,
  TextSwatch,
  Picker,
  PickerOption,
  ImageNodeRenderProps,
  Checkbox,
} from '@adobe-commerce/elsie/components';

import type {
  ProductOptionSelectionEntry,
  ProductOptionSelectionMap,
} from '@/pdp/lib/product-option-selection';

import '@/pdp/components/Swatches/Swatches.css';

export type {
  ProductOptionSelectionEntry as SelectionEntry,
  ProductOptionSelectionMap as Selection,
} from '@/pdp/lib/product-option-selection';

const supportedTypes = ['text', 'image', 'color', 'dropdown'];

const mapToPickerOptions = (items: OptionValue[]): PickerOption[] => {
  return items.map((item: OptionValue) => ({
    ...item,
    text: item.label,
    disabled: !item.inStock,
  }));
};

type OptionValue = {
  id: string;
  label: string;
  inStock: boolean;
  value: string;
  selected?: boolean;
};

export type Option = {
  id: string;
  type: (typeof supportedTypes)[number];
  label: string;
  required?: boolean;
  multiple?: boolean;
  items: OptionValue[];
};

function optionUIDsToSelection(
  optionUIDs: string[],
  options: Array<Option>
): ProductOptionSelectionMap {
  return options.reduce((accum, option) => {
    const selectedItems = option.items.filter((item) =>
      optionUIDs.includes(item.id)
    );
    if (selectedItems.length === 0) {
      return accum;
    }

    if (option.multiple) {
      return {
        ...accum,
        [option.id]: {
          label: selectedItems.map((i) => i.label).join(', '),
          values: selectedItems.map((i) => i.id),
        },
      };
    }

    const item = selectedItems[0];
    return {
      ...accum,
      [option.id]: { label: item.label, value: item.id },
    };
  }, {} as ProductOptionSelectionMap);
}

function getSingleSelectedValue(
  entry: ProductOptionSelectionEntry | undefined
): string | undefined {
  if (!entry || !('value' in entry)) {
    return undefined;
  }
  return entry.value;
}

export interface SwatchesProps extends HTMLAttributes<HTMLDivElement> {
  options: Array<Option>;
  hideSelectedValue?: boolean;
  disablePreselections?: boolean;
  defaultOptions?: string[];
  selectionsToUpdate?: Option[];
  onValues?: (uids: ProductOptionSelectionMap, current: string) => void;
  onErrors?: (errors: { [id: string]: string }) => void;
  selectedUIDs?: string[];
  imageSwatchNode?: VNode | ((props: ImageNodeRenderProps) => JSX.Element);
}

export const Swatches: FunctionComponent<SwatchesProps> = ({
  options,
  hideSelectedValue,
  disablePreselections,
  selectedUIDs,
  onValues,
  onErrors,
  defaultOptions,
  selectionsToUpdate,
  className,
  children,
  imageSwatchNode,
  ...props
}) => {
  // i18n
  const RequiredLabel = useText('PDP.Swatches.Required.label').label;
  const ChooseOptionLabel = useText('PDP.Swatches.ChooseOption.label').label;

  const [selections, setSelections] = useState<ProductOptionSelectionMap>(
    () => {
      let accum: ProductOptionSelectionMap =
        defaultOptions?.length && options?.length
          ? optionUIDsToSelection(defaultOptions, options)
          : {};

      options?.forEach((option) => {
        if (accum[option.id]) {
          return;
        }

        const { items } = option;

        if (option.multiple) {
          const picked = items?.filter(
            (item) =>
              Boolean(defaultOptions?.includes(item.id)) || item.selected
          );
          if (picked?.length) {
            accum = {
              ...accum,
              [option.id]: {
                label: picked.map((i) => i.label).join(', '),
                values: picked.map((i) => i.id),
              },
            };
          }
          return;
        }

        const defaultSelection = items?.find((item) =>
          defaultOptions?.includes(item.id)
        );
        const selected = items?.find((item) => item.selected);

        if (defaultSelection) {
          accum = {
            ...accum,
            [option.id]: {
              label: defaultSelection.label,
              value: defaultSelection.id,
            },
          };
        } else if (selected) {
          accum = {
            ...accum,
            [option.id]: { label: selected.label, value: selected.id },
          };
        }
      });

      return accum;
    }
  );

  // set selected options from props
  useEffect(() => {
    if (selectedUIDs) {
      const selection = optionUIDsToSelection(selectedUIDs, options);
      // if the internal state is already the same as the props, do nothing
      if (JSON.stringify(selection) === JSON.stringify(selections)) return;

      setSelections((prev) => {
        let next = {
          ...prev,
          ...selection,
        };
        onValues?.(next, selectedUIDs?.[0] ?? '');
        return next;
      });
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedUIDs]);

  // this only applies for the case with anchor options
  // update selections in the swatches if they are updated in the parent component
  useEffect(() => {
    selectionsToUpdate?.forEach((selectionToUpdate) => {
      setSelections((prev) => {
        const selectedItems = selectionToUpdate?.items?.filter(
          (item) => item.selected
        );
        if (!selectedItems?.length) return prev;

        if (selectionToUpdate.multiple) {
          const next = {
            ...prev,
            [selectionToUpdate.id]: {
              label: selectedItems.map((i) => i.label).join(', '),
              values: selectedItems.map((i) => i.id),
            },
          };
          return next;
        }

        const selectedItem = selectedItems[0];
        const next = {
          ...prev,
          [selectionToUpdate.id]: {
            label: selectedItem.label,
            value: selectedItem.id,
          },
        };
        return next;
      });
    });
  }, [selectionsToUpdate, setSelections]);

  // Update invalid options
  useMemo(() => {
    const errors = options?.reduce((accum, option) => {
      const entry = selections[option.id];
      let satisfied = false;

      if (option.multiple) {
        satisfied = Boolean(
          entry && 'values' in entry && entry.values.length > 0
        );
      } else {
        option?.items?.forEach((item) => {
          if (entry && 'value' in entry && entry.value === item.id) {
            satisfied = true;
          }
        });
      }

      if (option.required && !satisfied) {
        accum[option.id] = RequiredLabel;
      }
      return accum;
    }, {} as { [id: string]: string });

    onErrors?.(errors);

    return errors;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selections]);

  const handleOnSelection = useCallback(
    (optionGroupId: string, label: string, itemUid: string) => {
      setSelections((prev) => {
        let next: ProductOptionSelectionMap = {
          ...prev,
          ...(optionGroupId && { [optionGroupId]: { label, value: itemUid } }),
        };

        if (label === ChooseOptionLabel) {
          const rest = { ...next };
          delete rest[optionGroupId];
          next = rest;
        }

        onValues?.(next, itemUid);

        return next;
      });
    },
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [onValues]
  );

  const handleMultiToggle = useCallback(
    (
      optionGroupId: string,
      itemId: string,
      checked: boolean,
      groupItems: OptionValue[]
    ) => {
      setSelections((prev) => {
        const prevEntry = prev[optionGroupId];
        const prevValues: string[] =
          prevEntry && 'values' in prevEntry
            ? [...prevEntry.values]
            : prevEntry && 'value' in prevEntry && prevEntry.value
            ? [prevEntry.value]
            : [];

        const nextValues = checked
          ? [...new Set([...prevValues, itemId])]
          : prevValues.filter((v) => v !== itemId);

        const labelById = new Map(
          groupItems.map((i) => [i.id, i.label] as const)
        );
        const nextLabel = nextValues
          .map((uid) => labelById.get(uid))
          .filter(Boolean)
          .join(', ');

        const next: ProductOptionSelectionMap = { ...prev };
        if (nextValues.length === 0) {
          delete next[optionGroupId];
        } else {
          next[optionGroupId] = { label: nextLabel, values: nextValues };
        }
        onValues?.(next, itemId);
        return next;
      });
    },
    [onValues]
  );

  // Function to handle the picker selection
  const handlePickerSelect = useCallback(
    (optionId: string, selection: any) => {
      const label = selection.selectedOptions[0]?.label ?? '';
      handleOnSelection(optionId, label, selection.value);
    },
    [handleOnSelection]
  );

  const renderOptionControl = useCallback(
    ({
      items,
      id,
      required,
      type,
      selected,
      label,
      multiple,
    }: {
      items: OptionValue[];
      id: string;
      required?: boolean | null;
      type: string;
      selected?: string;
      label: string;
      multiple?: boolean;
    }) => {
      const uniqueId = `pdp-swatch-${id}=${Math.random().toString(36)}`;

      if (multiple) {
        const entry = selections[id];
        const selectedIds = new Set(
          entry && 'values' in entry ? entry.values : []
        );

        return (
          items?.length > 0 && (
            <div
              className={classes([
                'pdp-swatches__options',
                'pdp-swatches__options--checkboxes',
              ])}
            >
              {items?.map((option: OptionValue) => (
                <Checkbox
                  key={option.id}
                  name={`pdp-bundle-multi__${id}__${option.id}`}
                  label={option.label}
                  checked={selectedIds.has(option.id)}
                  disabled={!option.inStock}
                  onChange={(e: ChangeEvent<HTMLInputElement>) =>
                    handleMultiToggle(
                      id,
                      option.id,
                      e.currentTarget.checked,
                      items
                    )
                  }
                />
              ))}
            </div>
          )
        );
      }

      return (
        items?.length > 0 && (
          <div className={classes(['pdp-swatches__options'])}>
            {type?.toLowerCase() === 'dropdown' ? (
              <Picker
                id={uniqueId}
                name={id}
                aria-label={label}
                placeholder={
                  disablePreselections ? ChooseOptionLabel : undefined
                }
                handleSelect={(event) => handlePickerSelect(id, event.target)}
                options={mapToPickerOptions(items)}
                value={selected}
              />
            ) : (
              items?.map((option: OptionValue) => {
                const common = {
                  key: option.id,
                  id: `${uniqueId}-${option.id}`,
                  name: id,
                  value: option.value,
                  label: option.label,
                  groupAriaLabel: label,
                  selected: selected === option.id,
                  outOfStock: !option.inStock,
                  // API may return null, we default to true as all swatches are required.
                  //  we still comply to this in case the api return "false".
                  required: required === null ? true : required,
                  onValue: () => {
                    handleOnSelection(id, option.label, option.id);
                  },
                };

                switch (type) {
                  case 'text':
                    return <TextSwatch {...common} label={option.label} />;

                  case 'image':
                    return (
                      <ImageSwatch
                        {...common}
                        src={option.value}
                        alt={option.label}
                        imageNode={imageSwatchNode}
                      />
                    );

                  case 'color':
                    return (
                      <ColorSwatch
                        {...common}
                        size="large"
                        color={option.value}
                      />
                    );

                  default:
                    console.warn(`Invalid swatch type ${type}`);
                    return null;
                }
              })
            )}
          </div>
        )
      );
    },
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [
      ChooseOptionLabel,
      handleOnSelection,
      handlePickerSelect,
      handleMultiToggle,
      selections,
    ]
  );

  return (
    <div {...props} className={classes(['pdp-swatches', className])}>
      {options?.map(({ type, label, id, multiple, required, items }) => {
        // Only render supported types
        if (!supportedTypes.includes(type)) {
          console.warn(`Invalid swatch type ${type}`);
        }

        return (
          <div
            key={`swatch-item-${id}`}
            id={`swatch-item-${id}`}
            data-slot-key={`product-swatch--${id}`}
            className="pdp-swatches__field"
          >
            <div className="pdp-swatches__field__label">
              {selections[id]
                ? hideSelectedValue
                  ? `${label}`
                  : `${label}: ${selections[id].label}`
                : label}
            </div>

            {renderOptionControl({
              id,
              type,
              required,
              items,
              label,
              multiple,
              selected: getSingleSelectedValue(selections[id]),
            })}
          </div>
        );
      })}
    </div>
  );
};
